// Deadlock example
Object lock1 = new Object(), lock2 = new Object();

Thread t1 = new Thread(() -> {
  synchronized (lock1) {
    Thread.sleep(10);  // gives t2 time to grab lock2
    synchronized (lock2) { /* work */ }  // WAITS forever
  }
});

Thread t2 = new Thread(() -> {
  synchronized (lock2) {
    Thread.sleep(10);
    synchronized (lock1) { /* work */ }  // WAITS forever
  }
});

// Fix: consistent ordering — always acquire lock1 before lock2
Thread fixed1 = new Thread(() -> {
  synchronized (lock1) { synchronized (lock2) { /* work */ } }
});
Thread fixed2 = new Thread(() -> {
  synchronized (lock1) { synchronized (lock2) { /* work */ } }  // same order
});

// ReentrantLock with tryLock timeout
ReentrantLock l1 = new ReentrantLock(), l2 = new ReentrantLock();
if (l1.tryLock(1, TimeUnit.SECONDS)) {
  try {
    if (l2.tryLock(1, TimeUnit.SECONDS)) {
      try { /* work */ } finally { l2.unlock(); }
    }
  } finally { l1.unlock(); }
}

// Without volatile — thread may never see running = false
class BadWorker implements Runnable {
  private boolean running = true;  // cached in thread
  public void stop() { running = false; }
  public void run() {
    while (running) { /* work */ }  // may loop forever
  }
}

// With volatile — guaranteed visibility
class GoodWorker implements Runnable {
  private volatile boolean running = true;  // always read from main memory
  public void stop() { running = false; }
  public void run() {
    while (running) { /* work */ }  // sees update correctly
  }
}

// Singleton double-checked locking (Java 5+)
class Singleton {
  private static volatile Singleton instance;  // volatile needed
  public static Singleton getInstance() {
    if (instance == null) {
      synchronized (Singleton.class) {
        if (instance == null) {
          instance = new Singleton();  // without volatile, partially init object visible
        }
      }
    }
    return instance;
  }
}

